#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $q = CGI->new;
my $log_dir = '/path/to/logs';
my $filename = $q->param('logfile') || die "No logfile specified";

open(my $fh, "$log_dir/$filename") or die "Cannot open file: $!";
